const initializeHeaderScripts=()=>{const navToggle=document.querySelector(".mobile-nav-toggle");const mainNav=document.querySelector(".main-nav");const overlay=document.querySelector(".nav-overlay");if(!mainNav)return;const resetSlides=()=>{mainNav.querySelectorAll(".slide-active").forEach(el=>el.classList.remove("slide-active"))};const getParentSlideMenu=menu=>menu?.parentElement?.closest(".dropdown-menu, .submenu");const setActiveSlideMenu=targetMenu=>{if(!targetMenu)return;const activePath=[];let cursor=targetMenu;while(cursor){const isMenu=cursor.classList&&(cursor.classList.contains("dropdown-menu")||cursor.classList.contains("submenu"));if(isMenu)activePath.push(cursor);cursor=getParentSlideMenu(cursor)}resetSlides();activePath.reverse().forEach(menu=>{menu.classList.add("slide-active");const parentMenu=getParentSlideMenu(menu)||document.querySelector(".main-nav");if(parentMenu&&parentMenu!==menu){menu.style.top=parentMenu.scrollTop+"px"}});targetMenu.scrollTop=0};const closeMenu=()=>{mainNav.classList.remove("active");navToggle?.classList.remove("active");document.body.classList.remove("nav-open");resetSlides();mainNav.querySelectorAll(".dropdown.open, .dropdown-submenu.open").forEach(item=>{item.classList.remove("open")})};if(navToggle){navToggle.addEventListener("click",e=>{e.stopPropagation();const isOpening=!mainNav.classList.contains("active");if(isOpening){mainNav.classList.add("active");navToggle.classList.add("active");document.body.classList.add("nav-open")}else{closeMenu()}})}overlay?.addEventListener("click",closeMenu);document.addEventListener("keydown",e=>{if(e.key==="Escape"&&mainNav.classList.contains("active")){closeMenu()}});mainNav.querySelectorAll(".nav-links a:not(.dropdown-trigger)").forEach(link=>{const parentLi=link.closest("li");const hasSubmenu=parentLi&&parentLi.classList.contains("dropdown-submenu");if(!hasSubmenu){link.addEventListener("click",closeMenu)}});const normalizePath=rawPath=>{if(!rawPath)return"/";let path=rawPath.toLowerCase();if(path.startsWith("http://")||path.startsWith("https://")){try{path=new URL(path).pathname.toLowerCase()}catch(e){path="/"}}path=path.replace(/\/index\.html?$/,"/");path=path.replace(/\.html$/,"");if(path.length>1)path=path.replace(/\/+$/,"");return path||"/"};const currentPath=normalizePath(window.location.pathname);const isServicesPath=currentPath==="/service"||currentPath.startsWith("/services");mainNav.querySelectorAll(".nav-links > li").forEach(li=>{li.classList.remove("active")});mainNav.querySelectorAll(".nav-links > li > a[href]").forEach(link=>{const href=link.getAttribute("href");const hrefPath=normalizePath(href);let isActive=false;if(currentPath==="/"){isActive=hrefPath==="/"}else if(isServicesPath){isActive=hrefPath==="/service"||hrefPath==="/services"}else{isActive=hrefPath!=="/"&&(currentPath===hrefPath||currentPath.startsWith(`${hrefPath}/`))}if(isActive){link.closest("li").classList.add("active")}});const allSubmenus=mainNav.querySelectorAll(".dropdown-menu, .submenu");allSubmenus.forEach(menu=>{let hasBackBtn=false;for(let i=0;i<menu.children.length;i++){if(menu.children[i].classList.contains("mobile-back-btn")){hasBackBtn=true;break}}if(!hasBackBtn){const backBtn=document.createElement("li");backBtn.className="mobile-back-btn";backBtn.innerHTML='<i class="fas fa-chevron-left"></i> Back';backBtn.addEventListener("click",e=>{e.stopPropagation();const parentMenu=getParentSlideMenu(menu);if(parentMenu){setActiveSlideMenu(parentMenu)}else{resetSlides()}});menu.insertBefore(backBtn,menu.firstChild)}});const dropdownTrigger=mainNav.querySelector(".dropdown-trigger");if(dropdownTrigger){const newTrigger=dropdownTrigger.cloneNode(true);dropdownTrigger.parentNode.replaceChild(newTrigger,dropdownTrigger);newTrigger.addEventListener("click",e=>{if(window.innerWidth<=1024){e.preventDefault();e.stopPropagation();const targetMenu=newTrigger.nextElementSibling;if(targetMenu){setActiveSlideMenu(targetMenu)}}})}const nestedTriggers=mainNav.querySelectorAll("li > a");nestedTriggers.forEach(trigger=>{const siblingMenu=trigger.nextElementSibling;const isMenuTrigger=siblingMenu&&(siblingMenu.classList.contains("submenu")||siblingMenu.classList.contains("dropdown-menu"));const isNotTopLevel=!trigger.classList.contains("dropdown-trigger");if(isMenuTrigger&&isNotTopLevel){if(!trigger.dataset.mobileDrillInit){trigger.dataset.mobileDrillInit="true";trigger.addEventListener("click",e=>{if(window.innerWidth<=1024){e.preventDefault();e.stopPropagation();setActiveSlideMenu(siblingMenu)}})}}});if(navToggle){navToggle.addEventListener("click",()=>{if(mainNav.classList.contains("active")){setTimeout(resetSlides,400)}})}if(overlay){overlay.addEventListener("click",()=>{setTimeout(resetSlides,400)})}window.addEventListener("resize",()=>{if(window.innerWidth>1024){resetSlides();if(mainNav.classList.contains("active")){mainNav.classList.remove("active");navToggle?.classList.remove("active");document.body.classList.remove("nav-open")}}});const isLocal=window.location.hostname==="127.0.0.1"||window.location.hostname==="localhost"||window.location.protocol==="file:";if(!isLocal&&window.location.pathname.endsWith(".html")){let cleanPath=window.location.pathname.replace(/\.html$/,"");if(cleanPath.endsWith("/index")){cleanPath=cleanPath.replace(/\/index$/,"/")}const searchParams=window.location.search||"";window.history.replaceState(null,"",cleanPath+searchParams)}};const ensureFavicon=()=>{const head=document.head;if(!head)return;const iconHref="/images/favicon.png?v=3";const manifestHref="/manifest.json";const ensureLink=(selector,rel,href,type)=>{let link=head.querySelector(selector);if(!link){link=document.createElement("link");link.rel=rel;if(type)link.type=type;head.appendChild(link)}link.href=href;return link};ensureLink('link[rel="icon"]',"icon",iconHref,"image/png");ensureLink('link[rel="shortcut icon"]',"shortcut icon",iconHref);ensureLink('link[rel="apple-touch-icon"]',"apple-touch-icon",iconHref);ensureLink('link[rel="manifest"]',"manifest",manifestHref)};const headerPromise=fetch("/fragments/header.html").then(res=>res.ok?res.text():Promise.reject(res.status)).catch(()=>"");const footerPromise=fetch("/fragments/footer.html").then(res=>res.ok?res.text():Promise.reject(res.status)).catch(()=>"");const hubPromise=fetch("/fragments/floating-hub.html").then(res=>res.ok?res.text():Promise.reject(res.status)).catch(()=>"");document.addEventListener("DOMContentLoaded",async()=>{ensureFavicon();const headerPlaceholder=document.getElementById("header-placeholder");if(headerPlaceholder){try{const headerContent=await headerPromise;if(headerContent){headerPlaceholder.innerHTML=headerContent}}catch(e){headerPlaceholder.innerHTML='<header class="site-header fallback"><div class="container"><a href="/">Home</a><a href="/services">Services</a><a href="/contact">Contact</a></div></header>'}}initializeHeaderScripts();const ensureSearchScripts=()=>{const scripts=["/js/search-data.js","/js/search.js"];let loadedCount=0;const onScriptLoad=src=>{loadedCount++;if(loadedCount===scripts.length){if(typeof window.initializeSearchEngine==="function"){window.initializeSearchEngine()}}};scripts.forEach(src=>{const existing=document.querySelector(`script[src="${src}"]`);if(!existing){const script=document.createElement("script");script.src=src;script.defer=true;script.onload=()=>onScriptLoad(src);script.onerror=()=>{};document.body.appendChild(script)}else{const isLoaded=src==="/js/search.js"&&typeof window.initializeSearchEngine==="function"||src==="/js/search-data.js"&&typeof SEARCH_DATA!=="undefined";if(isLoaded){onScriptLoad(src)}else{existing.addEventListener("load",()=>onScriptLoad(src));existing.addEventListener("error",()=>{})}}})};ensureSearchScripts();const footerPlaceholder=document.getElementById("footer-placeholder");if(footerPlaceholder){try{const footerContent=await footerPromise;if(footerContent){footerPlaceholder.innerHTML=footerContent}}catch(e){footerPlaceholder.innerHTML='<footer class="site-footer fallback-footer"><div class="container"><p>🏢 B2B Industrial - Contact: info@b2bindustrial.in | Security & Energy Services across India</p></div></footer>'}}try{const hubContent=await hubPromise;if(hubContent&&!document.querySelector(".floating-hub")){document.body.insertAdjacentHTML("beforeend",hubContent)}}catch(e){}const yearSpan=document.getElementById("copyright-year");if(yearSpan)yearSpan.textContent=(new Date).getFullYear();if("serviceWorker"in navigator){window.addEventListener("load",()=>{navigator.serviceWorker.register("/sw.js").then(()=>{}).catch(()=>{})})}});